-- Migration: create cnae_mcc table
-- 1410 rows imported from cnae-mcc.csv

CREATE TABLE cnae_mcc (
  id            SERIAL PRIMARY KEY,
  cnae          TEXT NOT NULL,
  cnae_activity TEXT NOT NULL,
  mcc           TEXT NOT NULL,
  mcc_activity  TEXT NOT NULL,
  status        TEXT NOT NULL CHECK (status IN ('regular', 'restrict', 'incentivized', 'prohibited'))
);

-- RLS
ALTER TABLE cnae_mcc ENABLE ROW LEVEL SECURITY;

-- Policy pública: leitura sem a coluna status
CREATE POLICY "public can read cnae_mcc"
  ON cnae_mcc FOR SELECT
  TO anon, authenticated
  USING (true);

-- Índices
CREATE INDEX idx_cnae_mcc_cnae ON cnae_mcc(cnae);
CREATE INDEX idx_cnae_mcc_mcc  ON cnae_mcc(mcc);
CREATE INDEX idx_cnae_mcc_status ON cnae_mcc(status);

